Here's your **3-card modern UI** — fully self-contained and ready to open in any browser! 🎨

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Modern 3 Card UI</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

    *, *::before, *::after {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    :root {
      --bg: #0f0f1a;
      --card-bg: rgba(255, 255, 255, 0.05);
      --card-border: rgba(255, 255, 255, 0.1);
      --card-hover-border: rgba(255, 255, 255, 0.25);
      --text-primary: #f0f0ff;
      --text-secondary: #a0a0c0;
      --accent-1: #7c3aed;
      --accent-2: #3b82f6;
      --accent-3: #06b6d4;
      --accent-4: #f472b6;
      --accent-5: #10b981;
      --accent-6: #f59e0b;
    }

    body {
      font-family: 'Inter', system-ui, sans-serif;
      background-color: var(--bg);
      min-height: 100vh;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      padding: 40px 20px;
      overflow-x: hidden;
    }

    /* Animated background blobs */
    body::before,
    body::after {
      content: '';
      position: fixed;
      border-radius: 50%;
      filter: blur(100px);
      opacity: 0.18;
      z-index: 0;
      animation: float 8s ease-in-out infinite alternate;
    }

    body::before {
      width: 500px;
      height: 500px;
      background: radial-gradient(circle, #7c3aed, #3b82f6);
      top: -100px;
      left: -100px;
    }

    body::after {
      width: 400px;
      height: 400px;
      background: radial-gradient(circle, #06b6d4, #f472b6);
      bottom: -100px;
      right: -100px;
      animation-delay: 3s;
    }

    @keyframes float {
      from { transform: translate(0, 0) scale(1); }
      to   { transform: translate(40px, 30px) scale(1.1); }
    }

    /* Page header */
    .page-header {
      text-align: center;
      margin-bottom: 50px;
      position: relative;
      z-index: 1;
      animation: fadeUp 0.7s ease both;
    }

    .page-header h1 {
      font-size: clamp(1.8rem, 4vw, 2.8rem);
      font-weight: 700;
      color: var(--text-primary);
      letter-spacing: -0.5px;
    }

    .page-header h1 span {
      background: linear-gradient(135deg, #7c3aed, #3b82f6, #06b6d4);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
    }

    .page-header p {
      margin-top: 10px;
      font-size: 1rem;
      color: var(--text-secondary);
      font-weight: 400;
    }

    /* Cards grid */
    .cards-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
      gap: 28px;
      max-width: 1050px;
      width: 100%;
      position: relative;
      z-index: 1;
    }

    /* Individual card */
    .card {
      background: var(--card-bg);
      border: 1px solid var(--card-border);
      border-radius: 24px;
      padding: 36px 30px;
      backdrop-filter: blur(18px);
      -webkit-backdrop-filter: blur(18px);
      transition: transform 0.35s ease, border-color 0.35s ease, box-shadow 0.35s ease;
      cursor: pointer;
      animation: fadeUp 0.7s ease both;
      position: relative;
      overflow: hidden;
    }

    .card:nth-child(1) { animation-delay: 0.1s; }
    .card:nth-child(2) { animation-delay: 0.2s; }
    .card:nth-child(3) { animation-delay: 0.3s; }

    .card::before {
      content: '';
      position: absolute;
      top: 0; left: 0;
      width: 100%; height: 3px;
      border-radius: 24px 24px 0 0;
      opacity: 0;
      transition: opacity 0.35s ease;
    }

    .card-1::before { background: linear-gradient(90deg, #7c3aed, #3b82f6); }
    .card-2::before { background: linear-gradient(90deg, #06b6d4, #10b981); }
    .card-3::before { background: linear-gradient(90deg, #f472b6, #f59e0b); }

    .card:hover {
      transform: translateY(-10px) scale(1.02);
      border-color: var(--card-hover-border);
      box-shadow: 0 30px 60px rgba(0, 0, 0, 0.4), 0 0 0 1px rgba(255,255,255,0.08);
    }

    .card:hover::before { opacity: 1; }

    /* Icon */
    .card-icon {
      width: 60px;
      height: 60px;
      border-radius: 16px;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 26px;
      margin-bottom: 22px;
      position: relative;
    }

    .card-1 .card-icon { background: linear-gradient(135deg, rgba(124,58,237,0.25), rgba(59,130,246,0.25)); }
    .card-2 .card-icon { background: linear-gradient(135deg, rgba(6,182,212,0.25), rgba(16,185,129,0.25)); }
    .card-3 .card-icon { background: linear-gradient(135deg, rgba(244,114,182,0.25), rgba(245,158,11,0.25)); }

    /* Badge */
    .card-badge {
      display: inline-block;
      font-size: 0.7rem;
      font-weight: 600;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      padding: 4px 12px;
      border-radius: 99px;
      margin-bottom: 14px;
    }

    .card-1 .card-badge { background: rgba(124,58,237,0.2); color: #a78bfa; }
    .card-2 .card-badge { background: rgba(6,182,212,0.2); color: #67e8f9; }
    .card-3 .card-badge { background: rgba(244,114,182,0.2); color: #f9a8d4; }

    /* Card text */
    .card-title {
      font-size: 1.35rem;
      font-weight: 700;
      color: var(--text-primary);
      margin-bottom: 10px;
      line-height: 1.3;
    }

    .card-desc {
      font-size: 0.92rem;
      color: var(--text-secondary);
      line-height: 1.7;
      margin-bottom: 24px;
    }

    /* Stats row */
    .card-stats {
      display: flex;
      gap: 20px;
      margin-bottom: 26px;
      padding: 16px;
      background: rgba(255,255,255,0.04);
      border-radius: 12px;
      border: 1px solid rgba(255,255,255,0.06);
    }

    .stat-item {
      flex: 1;
      text-align: center;
    }

    .stat-value {
      font-size: 1.2rem;
      font-weight: 700;
      color: var(--text-primary);
    }

    .card-1 .stat-value { color: #a78bfa; }
    .card-2 .stat-value { color: #67e8f9; }
    .card-3 .stat-value { color: #f9a8d4; }

    .stat-label {
      font-size: 0.72rem;
      color: var(--text-secondary);
      margin-top: 2px;
      font-weight: 500;
    }

    /* CTA Button */
    .card-btn {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
      width: 100%;
      padding: 13px 20px;
      border-radius: 12px;
      border: none;
      font-family: 'Inter', sans-serif;
      font-size: 0.9rem;
      font-weight: 600;
      cursor: pointer;
      transition: opacity 0.25s ease, transform 0.25s ease;
      letter-spacing: 0.01em;
    }

    .card-btn:hover { opacity: 0.88; transform: scale(0.98); }
    .card-btn:active { transform: scale(0.95); }

    .card-1 .card-btn { background: linear-gradient(135deg, #7c3aed, #3b82f6); color: #fff; }
    .card-2 .card-btn { background: linear-gradient(135deg, #06b6d4, #10b981); color: #fff; }
    .card-3 .card-btn { background: linear-gradient(135deg, #f472b6, #f59e0b); color: #fff; }

    /* Tags */
    .card-tags {
      display: flex;
      gap: 8px;
      flex-wrap: wrap;
      margin-bottom: 20px;
    }

    .tag {
      font-size: 0.72rem;
      padding: 4px 10px;
      border-radius: 99px;
      color: var(--text-secondary);
      background: rgba(255,255,255,0.06);
      border: 1px solid rgba(255,255,255,0.08);
    }

    /* Fade up animation */
    @keyframes fadeUp {
      from { opacity: 0; transform: translateY(30px); }
      to   { opacity: 1; transform: translateY(0); }
    }

    /* Responsive */
    @media (max-width: 680px) {
      .cards-grid { grid-template-columns: 1fr; }
      .card { padding: 28px 22px; }
    }
  </style>
</head>
<body>

  <div class="page-header">
    <h1>Modern <span>UI Cards</span></h1>
    <p>Beautifully crafted glassmorphism components for your next project</p>
  </div>

  <div class="cards-grid">

    <!-- Card 1 -->
    <div class="card card-1">
      <div class="card-icon">🚀</div>
      <div class="card-badge">Performance</div>
      <h2 class="card-title">Blazing Fast Delivery</h2>
      <p class="card-desc">Supercharge your workflow with lightning-speed deployments and seamless CI/CD pipelines built for modern teams.</p>
      <div class="card-tags">
        <span class="tag">CI/CD</span>
        <span class="tag">DevOps</span>
        <span class="tag">Automation</span>
      </div>
      <div class="card-stats">
        <div class="stat-item">
          <div class="stat-value">99.9%</div>
          <div class="stat-label">Uptime</div>
        </div>
        <div class="stat-item">
          <div class="stat-value">2.4s</div>
          <div class="stat-label">Avg Deploy</div>
        </div>
        <div class="stat-item">
          <div class="stat-value">12k+</div>
          <div class="stat-label">Projects</div>
        </div>
      </div>
      <button class="card-btn" onclick="alert('🚀 Launching Performance Mode!')">
        Get Started <span>→</span>
      </button>
    </div>

    <!-- Card 2 -->
    <div class="card card-2">
      <div class="card-icon">🌊</div>
      <div class="card-badge">Analytics</div>
      <h2 class="card-title">Deep Data Insights</h2>
      <p class="card-desc">Unlock powerful analytics and real-time visualizations that help you make smarter, data-driven decisions faster.</p>
      <div class="card-tags">
        <span class="tag">Real-time</span>
        <span class="tag">Charts</span>
        <span class="tag">Reports</span>
      </div>
      <div class="card-stats">
        <div class="stat-item">
          <div class="stat-value">5M+</div>
          <div class="stat-label">Events/Day</div>
        </div>
        <div class="stat-item">
          <div class="stat-value">48</div>
          <div class="stat-label">Dashboards</div>
        </div>
        <div class="stat-item">
          <div class="stat-value">0ms</div>
          <div class="stat-label">Latency</div>
        </div>
      </div>
      <button class="card-btn" onclick="alert('🌊 Diving into Analytics!')">
        Explore Insights <span>→</span>
      </button>
    </div>

    <!-- Card 3 -->
    <div class="card card-3">
      <div class="card-icon">🔐</div>
      <div class="card-badge">Security</div>
      <h2 class="card-title">Enterprise Security</h2>
      <p class="card-desc">Stay protected with end-to-end encryption, zero-trust architecture, and AI-powered threat detection 24/7.</p>
      <div class="card-tags">
        <span class="tag">Encryption</span>
        <span class="tag">Zero-Trust</span>
        <span class="tag">AI Guard</span>
      </div>
      <div class="card-stats">
        <div class="stat-item">
          <div class="stat-value">256-bit</div>
          <div class="stat-label">Encryption</div>
        </div>
        <div class="stat-item">
          <div class="stat-value">0</div>
          <div class="stat-label">Breaches</div>
        </div>
        <div class="stat-item">
          <div class="stat-value">SOC2</div>
          <div class="stat-label">Certified</div>
        </div>
      </div>
      <button class="card-btn" onclick="alert('🔐 Activating Security Shield!')">
        Secure Now <span>→</span>
      </button>
    </div>

  </div>

  <script>
    // Subtle parallax tilt effect on cards
    document.querySelectorAll('.card').forEach(card => {
      card.addEventListener('mousemove', (e) => {
        const rect = card.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const y = e.clientY - rect.top;
        const centerX = rect.width / 2;
        const centerY = rect.height / 2;
        const rotateX = ((y - centerY) / centerY) * -6;
        const rotateY = ((x - centerX) / centerX) * 6;
        card.style.transform = `translateY(-10px) scale(1.02) rotateX(${rotateX}deg) rotateY(${rotateY}deg)`;
      });

      card.addEventListener('mouseleave', () => {
        card.style.transform = '';
        card.style.transition = 'transform 0.5s ease, border-color 0.35s ease, box-shadow 0.35s ease';
      });

      card.addEventListener('mouseenter', () => {
        card.style.transition = 'transform 0.1s ease, border-color 0.35s ease, box-shadow 0.35s ease';
      });
    });
  </script>

</body>
</html>
```

